const morgan = require('morgan');

// Create a new winston logger instance
const logger = winston.createLogger({
    level: 'info',
    format: winston.format.json(),
    defaultMeta: { service: 'user-service' },
    transports: [
        new winston.transports.File({ filename: 'access.log', level: 'info' }),
    ],
});

// Create a morgan token for user-provided data
morgan.token('user_data', function getUserData(req) {
    return {
        username: req.body.username,
        ip: req.headers['x-forwarded-for'] || req.connection.remoteAddress,
        customHeaders: req.headers['X-Custom-Header']
    }
});

// Create an express application
const app = express();

// Use morgan middleware
app.use(morgan(':method :url :status :res[content-length] - :response-time ms :user_data', {
    stream: {
        write: message => logger.info(message.trim())
    }
}));

// User input route
app.post('/userinput', function (req, res) {
    logger.info(req.body);
    res.send('Received user input');
});

// Server listening
